// â”€â”€â”€ SNOWFLAKE COMPONENT â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
interface SnowflakeProps { x:number; size:number; duration:number; delay:number; opacity:number }

const Snowflake: React.FC<SnowflakeProps> = ({ x, size, duration, delay, opacity }) => {
  const shapes = ['*','*','*','*','*'];
  const shape  = shapes[Math.floor((x * size * delay) % shapes.length)];
  return (
    <div style={{
      position:'fixed', left:`${x}%`, top:-20, fontSize:size,
      color:C.snow, opacity,
      animation:`fr-snow ${duration}s ${delay}s linear infinite`,
      pointerEvents:'none', zIndex:3, userSelect:'none',
      textShadow:`0 0 8px rgba(168,216,234,.8)`,
    }}>{shape}</div>
  );
};

const SnowLayer: React.FC<{ count?: number }> = ({ count = 30 }) => {
  const flakes = useRef(Array.from({length:count},(_,i)=>({
    x:    (i*13.7+3)%97,
    size: 10+((i*7)%16),
    dur:  6+((i*3)%8),
    del:  (i*0.7)%9,
    op:   0.25+((i*0.17)%0.55),
  }))).current;
  return <>{flakes.map((f,i)=><Snowflake key={i} x={f.x} size={f.size} duration={f.dur} delay={f.del} opacity={f.op}/>)}</>;
};

