const InsertBlockButton: React.FC<{
  insertIdx: number;
  openInsertAt: number | null;
  setOpenInsertAt: (v: number | null) => void;
  BLOCK_TYPES: { type: string; label: string; def: any }[];
  onInsert: (type: string, def: any) => void;
}> = ({ insertIdx, openInsertAt, setOpenInsertAt, BLOCK_TYPES, onInsert }) => {
  const isOpen = openInsertAt === insertIdx;
  const [hovered, setHovered] = React.useState(false);
  const visible = hovered || isOpen;
  return (
    <div
      style={{ position: "relative", display: "flex", alignItems: "center", justifyContent: "center", height: 32, zIndex: 20 }}
      onMouseEnter={() => setHovered(true)}
      onMouseLeave={() => setHovered(false)}
    >
      <div style={{
        position: "absolute", left: 0, right: 0, height: 1,
        background: `repeating-linear-gradient(to right, ${C.crystal} 0, ${C.crystal} 6px, transparent 6px, transparent 12px)`,
        opacity: 1, transition: "opacity 0.15s", zIndex: 1
      }} />
      <button
        type="button"
        onClick={() => setOpenInsertAt(isOpen ? null : insertIdx)}
        style={{
          width: 26, height: 26, borderRadius: "50%",
          background: isOpen ? C.iceDeep : "white",
          border: `1.5px solid ${C.crystal}`,
          cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "center",
          fontSize: 16, color: isOpen ? "white" : C.iceDeep,
          boxShadow: "0 2px 10px rgba(0,0,0,0.12)",
          opacity: 1,
          transition: "opacity 0.15s, transform 0.15s, background 0.15s",
          transform: visible ? "scale(1)" : "scale(0.7)",
          zIndex: 2, position: "relative",
          lineHeight: 1, fontWeight: 700,
        }}
      >{isOpen ? "x" : "+"}</button>

      {isOpen && (
        <div
          style={{
            position: "absolute", bottom: 34, left: "50%", transform: "translateX(-50%)",
            background: "white",
            borderRadius: 16,
            border: `1px solid ${C.crystal}`,
            boxShadow: "0 16px 48px rgba(15, 60, 100, 0.18), 0 4px 16px rgba(0,0,0,0.06)",
            padding: "16px",
            zIndex: 100,
            width: 260,
          }}
          onMouseEnter={() => setHovered(true)}
          onMouseLeave={() => setHovered(false)}
        >
          <p style={{ fontFamily: F.label, fontSize: "0.5rem", fontWeight: 700, letterSpacing: "0.3em", textTransform: "uppercase", color: C.iceDeep, margin: "0 0 10px", textAlign: "center" }}>
            Adauga bloc
          </p>
          <div style={{ display: "grid", gridTemplateColumns: "repeat(3, 1fr)", gap: 6 }}>
            {BLOCK_TYPES.map(bt => (
              <button key={bt.type} type="button" onClick={() => onInsert(bt.type, bt.def)}
                style={{
                  background: C.snowBlue,
                  border: `1px solid ${C.crystal}`,
                  borderRadius: 10, padding: "8px 4px", cursor: "pointer",
                  display: "flex", flexDirection: "column", alignItems: "center", gap: 4,
                  transition: "background 0.15s, border-color 0.15s",
                }}
                onMouseEnter={e => { (e.currentTarget as HTMLButtonElement).style.background = C.crystalPale; (e.currentTarget as HTMLButtonElement).style.borderColor = C.iceDeep; }}
                onMouseLeave={e => { (e.currentTarget as HTMLButtonElement).style.background = C.snowBlue; (e.currentTarget as HTMLButtonElement).style.borderColor = C.crystal; }}
              >
                <span style={{ fontSize: 18, lineHeight: 1 }}>{BLOCK_TYPE_ICONS[bt.type] || "+"}</span>
                <span style={{ fontFamily: F.label, fontSize: "0.5rem", fontWeight: 700, letterSpacing: "0.1em", textTransform: "uppercase", color: C.iceDeep, lineHeight: 1.2, textAlign: "center" }}>
                  {bt.label.replace(/^[^\s]+\s/, "")}
                </span>
              </button>
            ))}
          </div>
        </div>
      )}
    </div>
  );
};

// Ã¢â€â‚¬Ã¢â€â‚¬ Simple photo block Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬
const PhotoBlock: React.FC<{
  imageData?: string;
  altText?: string;
  editMode: boolean;
  onUpload: (url: string) => void;
  onAltChange: (v: string) => void;
  onRemove: () => void;
  aspectRatio?: "1:1" | "4:3" | "3:4" | "16:9" | "free";
}> = ({ imageData, altText, editMode, onUpload, onAltChange, onRemove, aspectRatio = "free" }) => {
  const fileRef = useRef<HTMLInputElement>(null);
  const [uploading, setUploading] = useState(false);
  const pt: Record<string, string> = { "1:1": "100%", "4:3": "75%", "3:4": "133%", "16:9": "56.25%", free: "66.6%" };

  const handleFile = async (file: File) => {
    if (!file.type.startsWith("image/")) return;
    setUploading(true);
    deleteUploadedFile(imageData);
    try {
      const form = new FormData();
      form.append("file", file);
      const _s = JSON.parse(localStorage.getItem("weddingPro_session") || "{}");
      const res = await fetch(`${API_URL}/upload`, {
        method: "POST",
        headers: { Authorization: `Bearer ${_s?.token || ""}` },
        body: form,
      });
      if (!res.ok) throw new Error("Image upload failed");
      const { url } = await res.json();
      onUpload(url);
    } catch (e) {
      console.error("Image upload:", e);
    } finally {
      setUploading(false);
    }
  };

  return (
    <div>
      <div style={{ position: "relative", borderRadius: 16, overflow: "hidden", border: `1.5px solid ${C.crystal}`, boxShadow: "0 6px 18px rgba(0,0,0,.35)" }}>
        <div style={{ position: "relative", paddingTop: pt[aspectRatio], overflow: "hidden" }}>
          {imageData ? (
            <img src={imageData} alt={altText || ""} style={{ position: "absolute", inset: 0, width: "100%", height: "100%", objectFit: "cover", display: "block" }} />
          ) : (
            <div
              style={{ position: "absolute", inset: 0, display: "flex", alignItems: "center", justifyContent: "center", background: `linear-gradient(135deg,${C.iceMid},${C.iceDeep})`, color: C.crystal, cursor: editMode ? "pointer" : "default" }}
              onClick={editMode ? () => fileRef.current?.click() : undefined}
            >
              {uploading ? (
                <div className="w-8 h-8 border-4 border-white border-t-transparent rounded-full animate-spin" />
              ) : (
                <div style={{ textAlign: "center" }}>
                  <Upload className="w-8 h-8" style={{ margin: "0 auto 6px", opacity: 0.85 }} />
                  <span style={{ fontFamily: F.label, fontSize: 10, letterSpacing: "0.2em", textTransform: "uppercase" }}>Adauga imagine</span>
                </div>
              )}
            </div>
          )}

          {editMode && imageData && (
            <div className="absolute inset-0 bg-black/35 opacity-0 hover:opacity-100 transition-opacity flex items-center justify-center gap-2">
              <button type="button" onClick={() => fileRef.current?.click()} className="p-2 bg-white rounded-full text-sky-600"><Camera className="w-5 h-5" /></button>
              <button
                type="button"
                onClick={() => {
                  deleteUploadedFile(imageData);
                  onRemove();
                }}
                className="p-2 bg-white rounded-full text-red-600"
              >
                <Trash2 className="w-5 h-5" />
              </button>
            </div>
          )}
        </div>
      </div>

      <input
        ref={fileRef}
        type="file"
        accept="image/*"
        onChange={e => {
          const f = e.target.files?.[0];
          if (f) handleFile(f);
        }}
        style={{ display: "none" }}
      />

      {editMode && (
        <div style={{ marginTop: 8 }}>
          <InlineEdit
            tag="p"
            editMode={editMode}
            value={altText || ""}
            onChange={(v) => onAltChange(v)}
            placeholder="Text alternativ..."
            textLabel="Foto · alt"
            style={{ fontFamily: F.body, fontSize: 11, color: C.crystal, margin: 0, textAlign: "center" }}
          />
        </div>
      )}
    </div>
  );
};

const MusicBlock: React.FC<{
  block: InvitationBlock;
  editMode: boolean;
  onUpdate: (p: Partial<InvitationBlock>) => void;
  imperativeRef?: React.MutableRefObject<{ unlock: () => void; play: () => void; pause: () => void } | null>;
}> = ({ block, editMode, onUpdate, imperativeRef }) => {
  const audioRef = useRef<HTMLAudioElement>(null);
  const mp3Ref = useRef<HTMLInputElement>(null);
  const [playing, setPlaying] = useState(false);
  const [progress, setProgress] = useState(0);
  const [duration, setDuration] = useState(0);
  const [uploading, setUploading] = useState(false);

  useEffect(() => {
    const a = audioRef.current;
    if (!a) return;
    const onTime = () => setProgress(a.currentTime);
    const onDur = () => setDuration(a.duration);
    const onEnd = () => {
      setPlaying(false);
      setProgress(0);
    };
    const onPlay = () => setPlaying(true);
    const onPause = () => setPlaying(false);
    a.addEventListener("timeupdate", onTime);
    a.addEventListener("loadedmetadata", onDur);
    a.addEventListener("ended", onEnd);
    a.addEventListener("play", onPlay);
    a.addEventListener("pause", onPause);
    return () => {
      a.removeEventListener("timeupdate", onTime);
      a.removeEventListener("loadedmetadata", onDur);
      a.removeEventListener("ended", onEnd);
      a.removeEventListener("play", onPlay);
      a.removeEventListener("pause", onPause);
    };
  }, [block.musicUrl, block.musicType]);

  useEffect(() => {
    if (!imperativeRef) return;
    imperativeRef.current = {
      unlock: () => {
        if (block.musicType === "mp3" && audioRef.current && block.musicUrl) {
          audioRef.current
            .play()
            .then(() => {
              audioRef.current!.pause();
              audioRef.current!.currentTime = 0;
            })
            .catch(() => {});
        }
      },
      play: () => {
        if (audioRef.current && block.musicUrl) {
          audioRef.current.play().catch(() => {});
        }
      },
      pause: () => {
        if (audioRef.current) audioRef.current.pause();
      },
    };
  }, [imperativeRef, block.musicType, block.musicUrl]);

  const fmt = (s: number) => `${Math.floor(s / 60)}:${String(Math.floor(s % 60)).padStart(2, "0")}`;
  const pct = duration ? `${(progress / duration) * 100}%` : "0%";

  const toggle = () => {
    const a = audioRef.current;
    if (!a) return;
    if (playing) {
      a.pause();
      setPlaying(false);
    } else {
      a.play().then(() => setPlaying(true)).catch(() => {});
    }
  };

  const seek = (e: React.MouseEvent<HTMLDivElement>) => {
    if (!audioRef.current || !duration) return;
    const r = e.currentTarget.getBoundingClientRect();
    audioRef.current.currentTime = Math.max(0, Math.min(1, (e.clientX - r.left) / r.width)) * duration;
  };

  const handleMp3 = async (file: File) => {
    if (!file.type.startsWith("audio/")) return;
    setUploading(true);
    deleteUploadedFile(block.musicUrl);
    try {
      const form = new FormData();
      form.append("file", file);
      const _s = JSON.parse(localStorage.getItem("weddingPro_session") || "{}");
      const res = await fetch(`${API_URL}/upload`, {
        method: "POST",
        headers: { Authorization: `Bearer ${_s?.token || ""}` },
        body: form,
      });
      if (!res.ok) throw new Error("Audio upload failed");
      const { url } = await res.json();
      onUpdate({ musicUrl: url, musicType: "mp3" });
    } catch (e) {
      console.error("Audio upload:", e);
    } finally {
      setUploading(false);
    }
  };

  const isActive = !!block.musicUrl;
  const isPlaying = playing;

  return (
    <div style={{ background: "white", border: `1.5px solid ${isPlaying ? C.iceDeep : C.crystal}`, borderRadius: 16, padding: "20px 24px", transition: "border-color 0.4s, box-shadow 0.4s", boxShadow: isPlaying ? `0 0 0 3px ${hexToRgba(C.iceDeep, 0.15)}` : "none" }}>
      <style>{`@keyframes fr-music-bar{0%,100%{transform:scaleY(0.3)}50%{transform:scaleY(1)}}`}</style>
      {block.musicType === "mp3" && block.musicUrl && <audio ref={audioRef} src={block.musicUrl} preload="metadata" />}

      <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 16 }}>
        <div style={{ width: 32, height: 32, borderRadius: "50%", background: isPlaying ? C.iceDeep : C.snowBlue, border: `1.5px solid ${isPlaying ? C.iceDeep : C.crystal}`, display: "flex", alignItems: "center", justifyContent: "center", transition: "all 0.3s" }}>
          <Music className="w-4 h-4" style={{ color: isPlaying ? "white" : C.iceDeep }} />
        </div>
        <span style={{ fontFamily: F.label, fontSize: 10, fontWeight: 700, letterSpacing: "0.3em", textTransform: "uppercase", color: isPlaying ? C.iceDeep : C.iceMid, transition: "color 0.3s" }}>
          {isPlaying ? "Se reda acum" : "Melodia zilei"}
        </span>
        {isPlaying && (
          <div style={{ display: "flex", alignItems: "flex-end", gap: 2, height: 14, marginLeft: "auto" }}>
            {[0, 0.2, 0.1, 0.3].map((delay, i) => (
              <div key={i} style={{ width: 3, height: 14, background: C.iceDeep, borderRadius: 2, transformOrigin: "bottom", animation: `fr-music-bar 0.7s ease-in-out ${delay}s infinite` }} />
            ))}
          </div>
        )}
      </div>

      {!isActive && editMode && (
        <div>
          <div style={{ display: "flex", gap: 8 }}>
            <button
              type="button"
              onClick={() => mp3Ref.current?.click()}
              disabled={uploading}
              style={{ flex: 1, background: C.snowBlue, border: `1px dashed ${C.crystal}`, borderRadius: 10, padding: "14px 0", cursor: uploading ? "not-allowed" : "pointer", display: "flex", flexDirection: "column", alignItems: "center", gap: 6, opacity: uploading ? 0.7 : 1 }}
            >
              {uploading ? (
                <div className="w-5 h-5 border-2 border-sky-700 border-t-transparent rounded-full animate-spin" />
              ) : (
                <Upload className="w-5 h-5" style={{ color: C.iceDeep, opacity: 0.7 }} />
              )}
              <span style={{ fontFamily: F.label, fontSize: 9, color: C.iceMid, fontWeight: 700, letterSpacing: "0.2em", textTransform: "uppercase" }}>MP3</span>
            </button>
            <input
              ref={mp3Ref}
              type="file"
              accept="audio/*,.mp3"
              onChange={e => {
                const f = e.target.files?.[0];
                if (f) handleMp3(f);
              }}
              style={{ display: "none" }}
            />
          </div>
        </div>
      )}

      {!isActive && !editMode && (
        <div style={{ textAlign: "center", padding: "16px 0", opacity: 0.4 }}>
          <Music className="w-8 h-8" style={{ color: C.iceDeep, display: "block", margin: "0 auto 6px" }} />
          <p style={{ fontFamily: F.body, fontSize: 12, fontStyle: "italic", color: C.iceMid, margin: 0 }}>Melodia va aparea aici</p>
        </div>
      )}

      {isActive && (
        <div>
          <div style={{ display: "flex", alignItems: "center", gap: 14, marginBottom: 14 }}>
            <div style={{ width: 52, height: 52, borderRadius: 10, background: `linear-gradient(135deg, ${C.snowBlue}, ${C.crystalPale})`, flexShrink: 0, display: "flex", alignItems: "center", justifyContent: "center", border: `1.5px solid ${C.crystal}` }}>
              <Music className="w-5 h-5" style={{ color: C.iceDeep, opacity: 0.7 }} />
            </div>
            <div style={{ flex: 1, minWidth: 0 }}>
              <InlineEdit
                tag="p"
                editMode={editMode}
                value={block.musicTitle || ""}
                onChange={v => onUpdate({ musicTitle: v })}
                placeholder="Titlul melodiei..."
                textLabel="Muzica · titlu"
                style={{ fontFamily: F.display, fontSize: 14, fontStyle: "italic", color: C.iceDeep, margin: 0, lineHeight: 1.3 }}
              />
              <InlineEdit
                tag="p"
                editMode={editMode}
                value={block.musicArtist || ""}
                onChange={v => onUpdate({ musicArtist: v })}
                placeholder="Artist..."
                textLabel="Muzica · artist"
                style={{ fontFamily: F.body, fontSize: 10, color: C.iceMid, margin: "2px 0 0" }}
              />
            </div>
          </div>

          <div onClick={seek} style={{ height: 4, background: C.crystal, borderRadius: 99, marginBottom: 6, cursor: "pointer", position: "relative" }}>
            <div style={{ height: "100%", borderRadius: 99, background: C.iceDeep, width: pct, transition: "width 0.3s linear" }} />
            <div style={{ position: "absolute", top: "50%", transform: "translateY(-50%)", left: pct, marginLeft: -5, width: 10, height: 10, borderRadius: "50%", background: C.iceDeep, transition: "left 0.3s linear" }} />
          </div>

          <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 14 }}>
            <span style={{ fontFamily: F.body, fontSize: 9, color: C.iceMid }}>{fmt(progress)}</span>
            <span style={{ fontFamily: F.body, fontSize: 9, color: C.iceMid }}>{duration ? fmt(duration) : "--:--"}</span>
          </div>

          <div style={{ display: "flex", alignItems: "center", justifyContent: "center", gap: 20 }}>
            <button
              type="button"
              onClick={() => {
                const a = audioRef.current;
                if (a) a.currentTime = Math.max(0, a.currentTime - 10);
              }}
              style={{ background: "none", border: "none", cursor: "pointer", padding: 4, opacity: 0.5 }}
            >
              <SkipBack className="w-4 h-4" style={{ color: C.iceDeep }} />
            </button>
            <button
              type="button"
              onClick={toggle}
              style={{ width: 44, height: 44, borderRadius: "50%", background: C.iceDeep, border: "none", cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "center", boxShadow: `0 4px 16px ${hexToRgba(C.iceDeep, 0.35)}` }}
            >
              {isPlaying ? <Pause className="w-4 h-4" style={{ color: "white" }} /> : <Play className="w-4 h-4" style={{ color: "white", marginLeft: 2 }} />}
            </button>
            <button
              type="button"
              onClick={() => {
                const a = audioRef.current;
                if (a) a.currentTime = Math.min(duration || a.currentTime + 10, a.currentTime + 10);
              }}
              style={{ background: "none", border: "none", cursor: "pointer", padding: 4, opacity: 0.5 }}
            >
              <SkipForward className="w-4 h-4" style={{ color: C.iceDeep }} />
            </button>
          </div>

          {editMode && (
            <div style={{ marginTop: 12, textAlign: "center", display: "flex", justifyContent: "center", gap: 8 }}>
              <button
                type="button"
                onClick={() => mp3Ref.current?.click()}
                style={{ background: C.snowBlue, border: `1px solid ${C.crystal}`, borderRadius: 99, padding: "4px 14px", cursor: "pointer", fontFamily: F.label, fontSize: 9, color: C.iceMid, fontWeight: 700, letterSpacing: "0.08em", textTransform: "uppercase" }}
              >
                Schimba sursa
              </button>
              <button
                type="button"
                onClick={() => {
                  deleteUploadedFile(block.musicUrl);
                  onUpdate({ musicUrl: "", musicType: "none" as any });
                  setPlaying(false);
                  setProgress(0);
                  setDuration(0);
                }}
                style={{ background: "transparent", border: `1px dashed ${C.crystal}`, borderRadius: 99, padding: "4px 12px", cursor: "pointer", fontFamily: F.label, fontSize: 9, color: C.iceMid, fontWeight: 700, letterSpacing: "0.08em", textTransform: "uppercase" }}
              >
                Sterge
              </button>
              <input
                ref={mp3Ref}
                type="file"
                accept="audio/*,.mp3"
                onChange={e => {
                  const f = e.target.files?.[0];
                  if (f) handleMp3(f);
                }}
                style={{ display: "none" }}
              />
            </div>
          )}
        </div>
      )}
    </div>
  );
};
const CalendarMonth: React.FC<{ date: string | undefined }> = ({ date }) => {
  if (!date) return null;
  const d = new Date(date);
  const year = d.getFullYear(), month = d.getMonth(), day = d.getDate();
  const firstDay = new Date(year, month, 1).getDay();
  const daysInMonth = new Date(year, month + 1, 0).getDate();
  const monthNames = ['IANUARIE','FEBRUARIE','MARTIE','APRILIE','MAI','IUNIE','IULIE','AUGUST','SEPTEMBRIE','OCTOMBRIE','NOIEMBRIE','DECEMBRIE'];
  const dayLabels = ['L','M','M','J','V','S','D'];
  const startOffset = (firstDay + 6) % 7;
  const cells: (number | null)[] = [...Array(startOffset).fill(null), ...Array.from({ length: daysInMonth }, (_, i) => i + 1)];
  return (
    <div style={{ background: "white", borderRadius: 16, padding: 20, textAlign: "center", border: `1px solid ${C.crystal}` }}>
      <p style={{ fontFamily: F.label, fontSize: 10, fontWeight: 700, letterSpacing: "0.2em", color: C.iceDeep, marginBottom: 12 }}>{monthNames[month]} {year}</p>
      <div style={{ display: "grid", gridTemplateColumns: "repeat(7, 1fr)", gap: 6, marginBottom: 6 }}>
        {dayLabels.map((l, i) => <div key={`${l}-${i}`} style={{ fontSize: 9, fontWeight: 700, color: C.crystal }}>{l}</div>)}
      </div>
      <div style={{ display: "grid", gridTemplateColumns: "repeat(7, 1fr)", gap: 6 }}>
        {cells.map((cell, i) => {
          const isToday = cell === day;
          return <div key={i} style={{ height: 26, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 12, fontWeight: isToday ? 700 : 400, color: isToday ? "white" : cell ? C.iceDeep : "transparent", background: isToday ? C.iceBright : "transparent", borderRadius: "50%" }}>{cell || ""}</div>;
        })}
      </div>
    </div>
  );
};

